#include <iostream>

class Vector2D {
private:
    double x;
    double y;

public:
    Vector2D(double x_val, double y_val) : x(x_val), y(y_val) {}
    Vector2D(const Vector2D& other) : x(other.x), y(other.y) {}
    void print() const {
        std::cout << "Vector2D(" << x << ", " << y << ")" << std::endl;
    }
};

int main() {
    Vector2D v1(10.5, 20.3);
    std::cout << "v1: ";
    v1.print();

    Vector2D v2 = v1;
    std::cout << "v2 (copy of v1): ";
    v2.print();

    Vector2D v3(5.0, 7.0);
    std::cout << "v3: ";
    v3.print();

    return 0;
}
